import AsyncStorage from '@react-native-async-storage/async-storage';
import { Platform } from 'react-native';

class ProductionLogger {
  constructor() {
    this.logs = [];
    this.maxLogs = 1000;
  }

  logNetworkRequest(url, method, headers, body, response, error) {
    const logEntry = {
      timestamp: new Date().toISOString(),
      type: 'NETWORK_REQUEST',
      url,
      method,
      headers: JSON.stringify(headers),
      body: JSON.stringify(body),
      response: JSON.stringify(response),
      error: error ? JSON.stringify(error) : null,
      authToken: headers?.Authorization || headers?.authorization || 'No auth token',
    };
    
    console.log('[NETWORK REQUEST]', JSON.stringify(logEntry, null, 2));
    console.debug('Request URL:', url);
    console.debug('Request Headers:', headers);
    console.debug('Request Body:', body);
    console.debug('Response Data:', response);
    console.debug('Auth Token:', logEntry.authToken);
    
    this.addLog(logEntry);
  }

  logAsyncStorageOperation(operation, key, value, error) {
    const logEntry = {
      timestamp: new Date().toISOString(),
      type: 'ASYNC_STORAGE',
      operation,
      key,
      value: typeof value === 'object' ? JSON.stringify(value) : value,
      error: error ? JSON.stringify(error) : null,
    };
    
    console.log('[ASYNC STORAGE]', JSON.stringify(logEntry, null, 2));
    console.debug('Storage Operation:', operation);
    console.debug('Storage Key:', key);
    console.debug('Storage Value:', value);
    
    this.addLog(logEntry);
  }

  logUserAction(action, data, userData) {
    const logEntry = {
      timestamp: new Date().toISOString(),
      type: 'USER_ACTION',
      action,
      data: JSON.stringify(data),
      userData: JSON.stringify(userData),
      userId: userData?.id || userData?.userId || 'Unknown',
      userEmail: userData?.email || 'Unknown',
      userName: userData?.name || userData?.username || 'Unknown',
    };
    
    console.log('[USER ACTION]', JSON.stringify(logEntry, null, 2));
    console.debug('Action Type:', action);
    console.debug('Action Data:', data);
    console.debug('User Data:', userData);
    console.debug('User ID:', logEntry.userId);
    console.debug('User Email:', logEntry.userEmail);
    
    this.addLog(logEntry);
  }

  logStateChange(stateName, oldState, newState, userData) {
    const logEntry = {
      timestamp: new Date().toISOString(),
      type: 'STATE_CHANGE',
      stateName,
      oldState: JSON.stringify(oldState),
      newState: JSON.stringify(newState),
      userData: JSON.stringify(userData),
      userId: userData?.id || 'Unknown',
    };
    
    console.log('[STATE CHANGE]', JSON.stringify(logEntry, null, 2));
    console.debug('State Name:', stateName);
    console.debug('Old State:', oldState);
    console.debug('New State:', newState);
    console.debug('Associated User:', userData);
    
    this.addLog(logEntry);
  }

  addLog(logEntry) {
    this.logs.push(logEntry);
    if (this.logs.length > this.maxLogs) {
      this.logs.shift();
    }
  }

  getAllLogs() {
    return this.logs;
  }

  exportLogs() {
    const exportData = {
      platform: Platform.OS,
      platformVersion: Platform.Version,
      timestamp: new Date().toISOString(),
      logs: this.logs,
    };
    
    console.log('[EXPORTED LOGS]', JSON.stringify(exportData, null, 2));
    return JSON.stringify(exportData, null, 2);
  }

  clearLogs() {
    this.logs = [];
    console.log('[LOGS CLEARED]', new Date().toISOString());
  }
}

const logger = new ProductionLogger();

const originalFetch = global.fetch;
global.fetch = async function(...args) {
  const [url, options = {}] = args;
  const method = options.method || 'GET';
  const headers = options.headers || {};
  const body = options.body;
  
  console.log('[INTERCEPTED FETCH]', url, method);
  console.debug('Full Request:', { url, method, headers, body });
  
  try {
    const response = await originalFetch(...args);
    const clonedResponse = response.clone();
    
    let responseData;
    try {
      responseData = await clonedResponse.json();
      console.log('[API RESPONSE DATA]', JSON.stringify(responseData, null, 2));
      console.debug('Response Status:', response.status);
      console.debug('Response Headers:', response.headers);
    } catch (e) {
      responseData = await clonedResponse.text();
      console.log('[API RESPONSE TEXT]', responseData);
    }
    
    logger.logNetworkRequest(url, method, headers, body, responseData, null);
    
    return response;
  } catch (error) {
    console.log('[NETWORK ERROR]', error.message);
    console.debug('Error Details:', error);
    logger.logNetworkRequest(url, method, headers, body, null, error);
    throw error;
  }
};

