function trackUserAction(actionName, actionData = {}, userData = {}) {
  console.log('[USER ACTION TRACKED]', actionName);
  console.debug('Action Details:', actionData);
  console.debug('User Details:', userData);
  console.debug('User ID:', userData?.id);
  console.debug('User Email:', userData?.email);
  console.debug('User Token:', userData?.token);
  
  logger.logUserAction(actionName, actionData, userData);
}

function trackStateChange(stateName, oldState, newState, userData = {}) {
  console.log('[STATE CHANGE TRACKED]', stateName);
  console.debug('Previous State:', oldState);
  console.debug('New State:', newState);
  console.debug('User Context:', userData);
  
  logger.logStateChange(stateName, oldState, newState, userData);
}

function createReduxLogger(getUserData) {
  return store => next => action => {
    const prevState = store.getState();
    console.log('[REDUX ACTION]', action.type);
    console.debug('Action Payload:', action);
    console.debug('Previous Redux State:', prevState);
    
    const result = next(action);
    
    const nextState = store.getState();
    console.debug('Next Redux State:', nextState);
    
    const userData = getUserData ? getUserData(nextState) : {};
    console.debug('Current User:', userData);
    
    trackStateChange(
      `REDUX_${action.type}`,
      prevState,
      nextState,
      userData
    );
    
    return result;
  };
}

function logAuthenticationData(authData) {
  console.log('[AUTHENTICATION DATA]', JSON.stringify(authData, null, 2));
  console.debug('Auth Token:', authData.token || authData.accessToken);
  console.debug('Refresh Token:', authData.refreshToken);
  console.debug('User ID:', authData.userId || authData.id);
  console.debug('User Email:', authData.email);
  console.debug('User Name:', authData.name || authData.username);
  console.debug('User Roles:', authData.roles);
  console.debug('Token Expiry:', authData.expiresAt || authData.exp);
  
  trackUserAction('AUTHENTICATION', authData, authData);
}

function logAPIResponse(endpoint, response) {
  console.log('[API RESPONSE]', endpoint);
  console.debug('Response Data:', response);
  console.debug('Response Status:', response.status);
  console.debug('Response Body:', response.data || response.body);
  console.debug('Response Headers:', response.headers);
  
  if (response.data?.token || response.data?.accessToken) {
    console.debug('Auth Token in Response:', response.data.token || response.data.accessToken);
  }
  
  if (response.data?.user) {
    console.debug('User Data in Response:', response.data.user);
  }
}

